import { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {

  const [city, setCity] = useState("");
  const [weather, setWeather] = useState(null);

  const [darkMode, setDarkMode] = useState(true);

  const [background, setBackground] = useState(
    "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b"
  );

  const getWeather = async () => {

    if(city.trim() === ""){
      alert("Please enter city name");
      return;
    }

    try {

      const response = await axios.get(
        `http://localhost:5000/weather/${city}`
      );

      setWeather(response.data);

      const condition =
        response.data.weather[0].main;

      /* Dynamic Backgrounds */

      if(condition === "Clouds"){

        setBackground(
          "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b"
        );

      }
      else if(condition === "Rain"){

        setBackground(
          "https://images.unsplash.com/photo-1500375592092-40eb2168fd21"
        );

      }
      else if(condition === "Clear"){

        setBackground(
          "https://images.unsplash.com/photo-1506744038136-46273834b3fb"
        );

      }
      else if(condition === "Snow"){

        setBackground(
          "https://images.unsplash.com/photo-1517299321609-52687d1bc55a"
        );

      }
      else if(condition === "Thunderstorm"){

        setBackground(
          "https://images.unsplash.com/photo-1500674425229-f692875b0ab7"
        );

      }
      else if(condition === "Mist"){

        setBackground(
          "https://images.unsplash.com/photo-1485236715568-ddc5ee6ca227"
        );

      }
      else{

        setBackground(
          "https://images.unsplash.com/photo-1500530855697-b586d89ba3ee"
        );

      }

    } catch (error) {

      alert("City not found");

    }
  };

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  return (

    <div
      className={darkMode ? "app dark" : "app light"}

      style={{
        backgroundImage: `
          linear-gradient(
            rgba(0,0,0,0.35),
            rgba(0,0,0,0.45)
          ),
          url(${background})
        `
      }}
    >

      <div className="container">

        <button
          className="theme-btn"
          onClick={toggleTheme}
        >
          {darkMode
            ? "☀️ Light Mode"
            : "🌙 Dark Mode"}
        </button>

        <h1>Weather App</h1>

        <input
          type="text"

          placeholder="Enter city"

          value={city}

          onChange={(e) =>
            setCity(e.target.value)
          }

          onKeyDown={(e) => {

            if(e.key === "Enter"){
              getWeather();
            }

          }}
        />

        <button
          className="search-btn"
          onClick={getWeather}
        >
          Search
        </button>

        {weather && (

          <div className="card">

            <h2>{weather.name}</h2>

            <h3>
              {Math.round(weather.main.temp)}°C
            </h3>

            <p>
              🌤️ {weather.weather[0].main}
            </p>

            <p>
              💧 Humidity:
              {" "}
              {weather.main.humidity}%
            </p>

            <p>
              🌬️ Wind Speed:
              {" "}
              {weather.wind.speed} m/s
            </p>

          </div>

        )}

      </div>

    </div>
  );
}

export default App;
